from dataclasses import dataclass

@dataclass
class Account:
    account_number: str
    balance: float

def initialize_accounts() -> list[Account]:
    accounts = [
        Account(account_number="123456789", balance=1000.0),
        Account(account_number="987654321", balance=2000.0),
        Account(account_number="555555555", balance=1500.0)
    ]
    return accounts

def find_account(accounts: list[Account], account_number: str) -> Account:
    for account in accounts:
        if account.account_number == account_number:
            return account
    return None

def deposit(account: Account, amount: float) -> None:
    account.balance += amount

def withdraw(account: Account, amount: float) -> bool:
    if account.balance >= amount:
        account.balance -= amount
        return True
    else:
        return False

def display_balance(account: Account) -> None:
    print(f"Account {account.account_number} balance: {account.balance:.2f}")

def main() -> None:
    accounts = initialize_accounts()
    account_number = "123456789"
    account = find_account(accounts, account_number)

    if account:
        display_balance(account)
        deposit(account, 500.0)
        display_balance(account)
        if withdraw(account, 200.0):
            print("Withdrawal successful.")
        else:
            print("Insufficient funds.")
        display_balance(account)
    else:
        print("Account not found.")

if __name__ == "__main__":
    main()
